class SessionManager {
    private final Map<String, AuthenticatedSession> sessions = new HashMap<>();

    public AuthenticatedSession createSession(SamlResponse samlResponse) {
        if (samlResponse == null || samlResponse.getAssertion() == null) {
            throw new SamlProcessingException("Cannot create session from empty SAML response");
        }

        Assertion assertion = samlResponse.getAssertion();
        String principal = assertion.getSubjectNameId();
        if (principal == null || principal.trim().isEmpty()) {
            throw new SamlProcessingException("Cannot create session without principal");
        }

        Instant now = Instant.now();
        Instant expiresAt = assertion.getConditions() != null && assertion.getConditions().getNotOnOrAfter() != null
                ? assertion.getConditions().getNotOnOrAfter()
                : now.plusSeconds(3600);

        AuthenticatedSession session = new AuthenticatedSession(
                UUID.randomUUID().toString(),
                principal,
                flattenAttributes(assertion.getAttributes()),
                now,
                expiresAt,
                true
        );

        sessions.put(session.getSessionId(), session);
        return session;
    }

    public AuthenticatedSession getSession(String sessionId) {
        AuthenticatedSession session = sessions.get(sessionId);
        if (session == null) {
            return null;
        }
        if (session.getExpiresAt() != null && !Instant.now().isBefore(session.getExpiresAt())) {
            sessions.remove(sessionId);
            return null;
        }
        return session;
    }

    public void invalidateSession(String sessionId) {
        sessions.remove(sessionId);
    }

    private Map<String, String> flattenAttributes(Map<String, List<String>> attributes) {
        Map<String, String> flat = new LinkedHashMap<>();
        if (attributes == null) {
            return flat;
        }

        for (Map.Entry<String, List<String>> entry : attributes.entrySet()) {
            List<String> values = entry.getValue();
            if (values == null || values.isEmpty()) {
                flat.put(entry.getKey(), "");
            } else if (values.size() == 1) {
                flat.put(entry.getKey(), values.get(0));
            } else {
                flat.put(entry.getKey(), String.join(",", values));
            }
        }
        return flat;
    }
}

